const table = {};

class UnitConverter {
    constructor(value, unit) {
        this.value = value;
        if (unit) {
            this.currentUnit = unit;
        }
    }

    as(targetUnit) {
        this.targetUnit = targetUnit;
        return this;
    }

    is(currentUnit) {
        this.currentUnit = currentUnit;
        return this;
    }

    val() {
        const target = table[this.targetUnit];
        const current = table[this.currentUnit];
        if (target.base !== current.base) {
            msg.error = true
        }

        return this.value * (current.multiplier / target.multiplier);
    }

    toString() {
        return `${this.val()} ${this.targetUnit}`;
    }

    debug() {
        return `${this.value} ${this.currentUnit} is ${Math.round(this.val() * 100) / 100} ${this.targetUnit}`;
    }
}

UnitConverter.addUnit = (baseUnit, actualUnit, multiplier) => {
    table[actualUnit] = { base: baseUnit, actual: actualUnit, multiplier };
};

